INSERT INTO learning_resources (title, type, category, author, upload_date, views, status, url, description, content, upload_by) VALUES 
('2025年中央经济工作会议精神解读', 'video', 'policy', '中央党校', '2025-12-15', 0, 'published', NULL, '深入解读2025年中央经济工作会议精神，分析当前经济形势和政策方向。', '2025年中央经济工作会议于12月12日至14日在北京举行，会议总结了2025年经济工作，分析了当前经济形势，部署了2026年经济工作任务。会议强调要坚持稳中求进工作总基调，完整、准确、全面贯彻新发展理念，加快构建新发展格局，着力推动高质量发展。', NULL),
('新发展阶段党员教育手册', 'document', 'theory', '党建出版社', '2025-12-10', 0, 'published', NULL, '为适应新发展阶段要求而编写的党员教育重要参考资料。', '本手册旨在帮助广大党员深入学习贯彻习近平新时代中国特色社会主义思想，提高政治素质和理论水平，增强“四个意识”、坚定“四个自信”、做到“两个维护”。手册内容涵盖党的基本理论、路线方针政策、党章党规党纪等方面。', NULL),
('科技创新与高质量发展专题讲座', 'video', 'model', '中国科学技术协会', '2025-11-28', 0, 'published', NULL, '探讨科技创新在推动高质量发展中的重要作用和实践路径。', '本讲座邀请了多位知名科学家和企业家，围绕科技创新与高质量发展的主题，分享了最新的研究成果和实践经验。讲座内容包括人工智能、生物医药、新能源等前沿领域的发展趋势和应用前景。', NULL),
('数字经济时代的党建工作创新', 'article', 'theory', '中共中央党校党建部', '2025-11-20', 0, 'published', NULL, '分析数字经济时代党建工作面临的新挑战和新机遇，提出创新思路和方法。', '随着数字经济的快速发展，党建工作面临着新的挑战和机遇。本文从数字技术与党建工作的融合角度，探讨了如何利用大数据、人工智能等技术创新党建工作方式方法，提高党建工作的针对性和实效性。', NULL);